// T returns the UI string for key in lang, falling back to Russian then the key.
func T(lang, key string) string {
	if m, ok := messages[key]; ok {
		if v, ok := m[lang]; ok && v != "" {
			return v
		}
		if v, ok := m[LangRU]; ok && v != "" {
			return v
		}
	}
	return key
}
